sql:
SELECT sl.log_id, sl.method, sl.endpoint, sl.content_size
FROM server_logs sl
WHERE sl.endpoint = (SELECT endpoint_id FROM endpoints WHERE endpoint_path = '/shuttle/countdown/');

SELECT COUNT(DISTINCT host) AS unique_hosts_count
FROM server_logs
WHERE endpoint = 1;

SELECT COUNT(DISTINCT host) AS unique_host_count
FROM server_logs
WHERE status = (SELECT status_id FROM statuses WHERE status_code = 404);

SELECT AVG(response_time) 
FROM server_logs
WHERE status = (SELECT status_id FROM statuses WHERE status_code = 200);

SELECT COUNT(DISTINCT host)
FROM server_logs
WHERE protocol = (SELECT protocol_id FROM protocols WHERE protocol_name = 'HTTP/1.0');

SELECT host_name, ip_address
FROM hosts
WHERE host_id = 1;

external_knowledge:
- A slow request is often defined as a request that takes more than 500 milliseconds to process; 
- Response time is a measure of how long it takes for a server to process a request; 
- A high response time may indicate performance issues or high server load; 
- Cumulative content size refers to the total size of content returned by the server up to a certain log entry; 
- Geographic location can be important for analyzing server requests in terms of regional usage patterns or legal compliance.

sql:
SELECT endpoint_path, access_count 
FROM endpoints
ORDER BY access_count DESC;

SELECT endpoint_path
FROM endpoints
WHERE access_count > 50;

SELECT timestamp, user_agent
FROM server_logs
WHERE log_id = 0;
